{
  "name": "Acron Bank Demo",
  "description": "A high-fidelity frontend banking simulator for Acron Bank, featuring secure-style login, dashboard, transaction history, and a simulated transfer flow with receipt generation."
}

export type TransactionType = 'credit' | 'debit';
export type TransactionStatus = 'Completed' | 'Pending' | 'Failed';

export interface Transaction {
  id: number;
  date: string;
  description: string;
  amount: number;
  type: TransactionType;
  status: TransactionStatus;
}

export interface UserProfile {
  accountNumber: string;
  firstName: string;
  surname: string;
  email: string;
  age: number;
  currency: string;
  country: string;
  balance: number;
}

export interface TransferDetails {
  recipientName: string;
  recipientIban: string;
  bankName: string;
  amount: number;
  description: string;
  date: string;
  reference: string;
}

export type AppView = 'login' | 'dashboard' | 'transfer' | 'history' | 'receipt' | 'profile';

export const formatCurrency = (amount: number, currency: string = 'EUR') => {
  return new Intl.NumberFormat('fi-FI', {
    style: 'currency',
    currency: currency,
    minimumFractionDigits: 2
  }).format(amount);
};

export const generateReference = () => {
  return Math.random().toString(36).substring(2, 10).toUpperCase() + '-' + Date.now().toString().slice(-4);
};

export const formatDate = (dateString: string) => {
  return new Date(dateString).toLocaleDateString('fi-FI', {
    year: 'numeric',
    month: 'long',
    day: 'numeric'
  });
};

import React, { useState, useEffect } from 'react';
import { AppView, TransferDetails } from './types';
import { USER_CREDENTIALS, STATIC_USER } from './constants';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import TransferForm from './components/TransferForm';
import TransactionHistoryView from './components/TransactionHistoryView';
import Receipt from './components/Receipt';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import ProfileView from './components/ProfileView';

const App: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState<boolean>(() => {
    return localStorage.getItem('acron_auth') === 'true';
  });
  const [currentView, setCurrentView] = useState<AppView>('dashboard');
  const [lastTransfer, setLastTransfer] = useState<TransferDetails | null>(null);

  useEffect(() => {
    if (!isLoggedIn) {
      setCurrentView('login');
    }
  }, [isLoggedIn]);

  const handleLogin = (accountNumber: string) => {
    if (accountNumber === USER_CREDENTIALS) {
      setIsLoggedIn(true);
      localStorage.setItem('acron_auth', 'true');
      setCurrentView('dashboard');
      return true;
    }
    return false;
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    localStorage.removeItem('acron_auth');
    setCurrentView('login');
  };

  const handleTransferComplete = (details: TransferDetails) => {
    setLastTransfer(details);
    setCurrentView('receipt');
  };

  if (!isLoggedIn) {
    return <Login onLogin={handleLogin} />;
  }

  const renderView = () => {
    switch (currentView) {
      case 'dashboard':
        return <Dashboard 
          user={STATIC_USER} 
          onAction={(view) => setCurrentView(view as AppView)} 
        />;
      case 'transfer':
        return <TransferForm 
          onComplete={handleTransferComplete} 
          onCancel={() => setCurrentView('dashboard')} 
        />;
      case 'history':
        return <TransactionHistoryView />;
      case 'receipt':
        return lastTransfer ? (
          <Receipt 
            details={lastTransfer} 
            onClose={() => setCurrentView('dashboard')} 
          />
        ) : <Dashboard user={STATIC_USER} onAction={(v) => setCurrentView(v as AppView)} />;
      case 'profile':
        return <ProfileView user={STATIC_USER} />;
      default:
        return <Dashboard user={STATIC_USER} onAction={(v) => setCurrentView(v as AppView)} />;
    }
  };

  return (
    <div className="flex flex-col lg:flex-row min-h-screen bg-slate-50">
      <div className="no-print">
        <Sidebar currentView={currentView} setView={setCurrentView} onLogout={handleLogout} />
      </div>
      <div className="flex-1 flex flex-col min-w-0">
        <div className="no-print">
          <Header user={STATIC_USER} currentView={currentView} setView={setCurrentView} onLogout={handleLogout} />
        </div>
        <main className="flex-1 p-4 md:p-8 max-w-7xl mx-auto w-full">
          {renderView()}
        </main>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState } from 'react';
import { ShieldCheck, Landmark, AlertCircle } from 'lucide-react';

interface LoginProps {
  onLogin: (account: string) => boolean;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [accountNumber, setAccountNumber] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const success = onLogin(accountNumber);
    if (!success) {
      setError('Invalid account number. Please verify your credentials.');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-700 to-indigo-900 px-4">
      <div className="bg-white p-8 rounded-2xl shadow-2xl w-full max-w-md">
        <div className="flex flex-col items-center mb-8">
          <div className="bg-blue-600 p-3 rounded-xl mb-4 text-white">
            <Landmark size={40} />
          </div>
          <h1 className="text-3xl font-bold text-gray-900 tracking-tight">Acron Bank</h1>
          <p className="text-gray-500 mt-2 text-center">Private Banking Online Portal</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-2">
              Account Number
            </label>
            <input
              type="text"
              required
              className="w-full px-4 py-3 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-600 focus:border-transparent outline-none transition-all placeholder:text-gray-400"
              placeholder="e.g. FI74-XXXX-XXXX-XXXX"
              value={accountNumber}
              onChange={(e) => {
                setAccountNumber(e.target.value);
                setError('');
              }}
            />
          </div>

          {error && (
            <div className="flex items-center gap-2 text-red-600 bg-red-50 p-3 rounded-lg text-sm font-medium">
              <AlertCircle size={18} />
              {error}
            </div>
          )}

          <button
            type="submit"
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-4 rounded-lg transition-colors flex items-center justify-center gap-2 group shadow-lg"
          >
            Access My Account
            <ShieldCheck size={20} className="group-hover:scale-110 transition-transform" />
          </button>
        </form>

        <div className="mt-8 pt-8 border-t border-gray-100">
          <p className="text-xs text-center text-gray-400 leading-relaxed uppercase tracking-wider font-semibold">
            Member of Finnish Financial Supervisory Authority
          </p>
        </div>
      </div>
    </div>
  );
};

export default Login;

import React from 'react';
import { Transaction } from '../types';
import { ArrowUpRight, ArrowDownLeft, Calendar } from 'lucide-react';
import { formatCurrency, formatDate } from '../utils';

interface TransactionItemProps {
  transaction: Transaction;
}

const TransactionItem: React.FC<TransactionItemProps> = ({ transaction }) => {
  const isCredit = transaction.type === 'credit';

  return (
    <div className="px-6 py-4 flex items-center justify-between hover:bg-slate-50 transition-colors cursor-pointer group">
      <div className="flex items-center gap-4">
        <div className={`p-3 rounded-full ${isCredit ? 'bg-emerald-100 text-emerald-600' : 'bg-red-100 text-red-600'} group-hover:scale-110 transition-transform`}>
          {isCredit ? <ArrowUpRight size={20} /> : <ArrowDownLeft size={20} />}
        </div>
        <div>
          <h4 className="font-semibold text-gray-900 leading-none mb-1 line-clamp-1">{transaction.description}</h4>
          <div className="flex items-center gap-3 text-xs text-gray-500">
            <span className="flex items-center gap-1 font-medium">
              <Calendar size={12} />
              {formatDate(transaction.date)}
            </span>
            <span className="bg-gray-100 px-2 py-0.5 rounded text-[10px] uppercase font-bold tracking-wider">{transaction.status}</span>
          </div>
        </div>
      </div>
      <div className={`font-bold text-lg whitespace-nowrap ${isCredit ? 'text-emerald-600' : 'text-gray-900'}`}>
        {isCredit ? '+' : ''}{formatCurrency(transaction.amount)}
      </div>
    </div>
  );
};

export default TransactionItem;

import React, { useState } from 'react';
import { 
  ArrowLeft, 
  ChevronRight, 
  Loader2, 
  Lock, 
  Building, 
  User, 
  CreditCard, 
  MessageSquare,
  ArrowRight
} from 'lucide-react';
import { TransferDetails } from '../types';
import { FINNISH_BANKS } from '../constants';
import { generateReference } from '../utils';

interface TransferFormProps {
  onComplete: (details: TransferDetails) => void;
  onCancel: () => void;
}

type Step = 'form' | 'processing' | 'pin';

const TransferForm: React.FC<TransferFormProps> = ({ onComplete, onCancel }) => {
  const [step, setStep] = useState<Step>('form');
  const [pin, setPin] = useState('');
  const [formData, setFormData] = useState({
    recipientName: '',
    recipientIban: '',
    bankName: FINNISH_BANKS[0],
    amount: '',
    description: ''
  });

  const handleContinue = (e: React.FormEvent) => {
    e.preventDefault();
    setStep('processing');
    setTimeout(() => {
      setStep('pin');
    }, 1500);
  };

  const handlePinSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (pin.length === 4) {
      setStep('processing');
      setTimeout(() => {
        onComplete({
          ...formData,
          amount: parseFloat(formData.amount),
          date: new Date().toISOString(),
          reference: generateReference()
        });
      }, 2000);
    }
  };

  if (step === 'processing') {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] animate-in zoom-in duration-300">
        <Loader2 size={48} className="text-blue-600 animate-spin mb-6" />
        <h2 className="text-2xl font-bold text-gray-900">Transaction Processing...</h2>
        <p className="text-gray-500 mt-2">Communicating with SEPA gateway</p>
      </div>
    );
  }

  if (step === 'pin') {
    return (
      <div className="max-w-md mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500">
        <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-xl text-center">
          <div className="bg-blue-100 text-blue-600 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-6">
            <Lock size={32} />
          </div>
          <h2 className="text-2xl font-bold text-gray-900 mb-2">Enter Secure PIN</h2>
          <p className="text-gray-500 mb-8">Confirm this payment by entering your 4-digit master PIN code.</p>

          <form onSubmit={handlePinSubmit} className="space-y-6">
            <div className="flex justify-center gap-3">
              {[0, 1, 2, 3].map((i) => (
                <div key={i} className={`w-4 h-4 rounded-full border-2 border-blue-600 ${pin.length > i ? 'bg-blue-600' : 'bg-transparent'}`} />
              ))}
            </div>
            <input
              autoFocus
              type="password"
              maxLength={4}
              className="sr-only"
              value={pin}
              onChange={(e) => setPin(e.target.value.replace(/\D/g, ''))}
            />
            {/* Virtual Num Pad simulation logic could go here, but a hidden input works well for desktop keyboard use */}
            <div className="grid grid-cols-3 gap-3">
              {[1, 2, 3, 4, 5, 6, 7, 8, 9, 'C', 0, '✓'].map((num) => (
                <button
                  key={num}
                  type="button"
                  onClick={() => {
                    if (num === 'C') setPin('');
                    else if (num === '✓') handlePinSubmit({ preventDefault: () => {} } as any);
                    else if (pin.length < 4) setPin(prev => prev + num);
                  }}
                  className="h-14 bg-slate-50 hover:bg-slate-100 rounded-xl text-xl font-bold text-gray-700 active:scale-95 transition-all"
                >
                  {num}
                </button>
              ))}
            </div>

            <button
              disabled={pin.length < 4}
              className="w-full bg-blue-600 hover:bg-blue-700 disabled:bg-gray-300 text-white font-bold py-4 rounded-2xl shadow-lg transition-all flex items-center justify-center gap-2"
            >
              Verify & Complete Transfer
              <ArrowRight size={20} />
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto animate-in fade-in duration-500">
      <button 
        onClick={onCancel}
        className="flex items-center gap-2 text-gray-500 hover:text-gray-800 font-medium mb-6 transition-colors"
      >
        <ArrowLeft size={20} />
        Back to Dashboard
      </button>

      <div className="bg-white rounded-3xl border border-gray-100 shadow-xl overflow-hidden">
        <div className="bg-slate-50 p-6 border-b border-gray-100">
          <h2 className="text-xl font-bold text-gray-900">New Money Transfer</h2>
          <p className="text-sm text-gray-500">Funds will be available to the recipient shortly.</p>
        </div>

        <form onSubmit={handleContinue} className="p-8 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-sm font-semibold text-gray-700 flex items-center gap-2">
                <User size={16} className="text-blue-500" />
                Recipient Name
              </label>
              <input
                required
                className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-600 outline-none"
                placeholder="Full Name"
                value={formData.recipientName}
                onChange={e => setFormData({ ...formData, recipientName: e.target.value })}
              />
            </div>
            <div className="space-y-2">
              <label className="text-sm font-semibold text-gray-700 flex items-center gap-2">
                <Building size={16} className="text-blue-500" />
                Select Bank
              </label>
              <select
                className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-600 outline-none bg-white"
                value={formData.bankName}
                onChange={e => setFormData({ ...formData, bankName: e.target.value })}
              >
                {FINNISH_BANKS.map(bank => (
                  <option key={bank} value={bank}>{bank}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-sm font-semibold text-gray-700 flex items-center gap-2">
              <CreditCard size={16} className="text-blue-500" />
              Recipient IBAN
            </label>
            <input
              required
              className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-600 outline-none uppercase font-mono"
              placeholder="FIXX XXXX XXXX XXXX XX"
              value={formData.recipientIban}
              onChange={e => setFormData({ ...formData, recipientIban: e.target.value.toUpperCase() })}
            />
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-sm font-semibold text-gray-700">Amount (EUR)</label>
              <div className="relative">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-bold">€</span>
                <input
                  required
                  type="number"
                  step="0.01"
                  min="0.01"
                  className="w-full pl-8 pr-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-600 outline-none text-xl font-bold"
                  placeholder="0.00"
                  value={formData.amount}
                  onChange={e => setFormData({ ...formData, amount: e.target.value })}
                />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-semibold text-gray-700 flex items-center gap-2">
                <MessageSquare size={16} className="text-blue-500" />
                Message (Optional)
              </label>
              <input
                className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-600 outline-none"
                placeholder="Reference info"
                value={formData.description}
                onChange={e => setFormData({ ...formData, description: e.target.value })}
              />
            </div>
          </div>

          <button
            type="submit"
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-2xl shadow-lg transition-all flex items-center justify-center gap-2 group"
          >
            Review & Continue
            <ChevronRight size={20} className="group-hover:translate-x-1 transition-transform" />
          </button>
        </form>
      </div>
    </div>
  );
};

export default TransferForm;

import React, { useState } from 'react';
import { STATIC_TRANSACTIONS } from '../constants';
import TransactionItem from './TransactionItem';
import { Filter, Search, Download } from 'lucide-react';

const TransactionHistoryView: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');

  const filtered = STATIC_TRANSACTIONS.filter(tx => 
    tx.description.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Transaction History</h2>
          <p className="text-gray-500">Manage and track your account movements</p>
        </div>
        <button className="flex items-center gap-2 bg-white px-4 py-2 border border-gray-200 rounded-xl text-sm font-semibold text-gray-700 hover:bg-gray-50 transition-colors shadow-sm">
          <Download size={18} />
          Export Statements
        </button>
      </div>

      <div className="bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden">
        <div className="p-4 border-b border-gray-50 flex flex-col md:flex-row gap-4 items-center">
          <div className="relative flex-1 w-full">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
            <input
              className="w-full pl-11 pr-4 py-3 bg-slate-50 border-none rounded-xl focus:ring-2 focus:ring-blue-600 outline-none"
              placeholder="Search by description..."
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <button className="flex items-center gap-2 px-4 py-3 bg-slate-50 rounded-xl text-gray-600 font-semibold hover:bg-slate-100 transition-colors w-full md:w-auto justify-center">
            <Filter size={18} />
            Filters
          </button>
        </div>

        <div className="hidden md:grid grid-cols-12 px-6 py-3 bg-slate-50 text-[10px] font-bold text-gray-400 uppercase tracking-widest border-b border-gray-100">
          <div className="col-span-1">Status</div>
          <div className="col-span-2">Date</div>
          <div className="col-span-6">Description</div>
          <div className="col-span-3 text-right">Amount</div>
        </div>

        <div className="divide-y divide-gray-50">
          {filtered.length > 0 ? (
            filtered.map((tx) => (
              <TransactionItem key={tx.id} transaction={tx} />
            ))
          ) : (
            <div className="p-20 text-center text-gray-400">
              No transactions found matching your criteria.
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default TransactionHistoryView;

