            <div className="absolute bottom-8 left-8 right-8">
               <button 
                 onClick={onLogout}
                 className="w-full flex items-center justify-center gap-3 p-4 bg-red-50 text-red-600 rounded-2xl font-bold"
               >
                 <LogOut size={20} />
                 Sign Out
               </button>
            </div>
          </div>
        </div>
      )}
    </header>
  );
};

