import React, { useState } from 'react';
import { 
  ArrowLeft, 
  ChevronRight, 
  Loader2, 
  Lock, 
  Building, 
  User, 
  CreditCard, 
  MessageSquare,
  ArrowRight,
  Globe,
  Flag
} from 'lucide-react';
import { TransferDetails, TransferType } from '../types';
import { EU_BANKS, US_BANKS } from '../constants';
import { generateReference } from '../utils';

interface TransferFormProps {
  onComplete: (details: TransferDetails) => void;
  onCancel: () => void;
}

type Step = 'form' | 'processing' | 'pin';

const TransferForm: React.FC<TransferFormProps> = ({ onComplete, onCancel }) => {
  const [step, setStep] = useState<Step>('form');
  const [pin, setPin] = useState('');
  const [transferType, setTransferType] = useState<TransferType>('EU');
  const [formData, setFormData] = useState({
    recipientName: '',
    recipientIban: '',
    bicSwift: '',
    accountNumber: '',
    routingNumber: '',
    bankName: EU_BANKS[0],
    amount: '',
    description: ''
  });

  const handleTypeChange = (type: TransferType) => {
    setTransferType(type);
    setFormData(prev => ({
      ...prev,
      bankName: type === 'EU' ? EU_BANKS[0] : US_BANKS[0],
      recipientIban: '',
      bicSwift: '',
      accountNumber: '',
      routingNumber: ''
    }));
  };

  const handleContinue = (e: React.FormEvent) => {
    e.preventDefault();
    setStep('processing');
    setTimeout(() => {
      setStep('pin');
    }, 2500); // 2-3 second delay as requested
  };

  const handlePinSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (pin.length === 4) {
      setStep('processing');
      setTimeout(() => {
        onComplete({
          transferType,
          recipientName: formData.recipientName,
          bankName: formData.bankName,
          amount: parseFloat(formData.amount),
          description: formData.description,
          date: new Date().toISOString(),
          reference: generateReference(),
          recipientIban: transferType === 'EU' ? formData.recipientIban : undefined,
          bicSwift: transferType === 'EU' ? formData.bicSwift : undefined,
          accountNumber: transferType === 'US' ? formData.accountNumber : undefined,
          routingNumber: transferType === 'US' ? formData.routingNumber : undefined,
        });
      }, 2000);
    }
  };

  if (step === 'processing') {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] animate-in zoom-in duration-300">
        <Loader2 size={48} className="text-blue-600 animate-spin mb-6" />
        <h2 className="text-2xl font-bold text-gray-900">Processing transaction...</h2>
        <p className="text-gray-500 mt-2">Communicating with global SEPA/SWIFT gateway</p>
      </div>
    );
  }

  if (step === 'pin') {
    return (
      <div className="max-w-md mx-auto animate-in fade-in slide-in-from-bottom-4 duration-500">
        <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-xl text-center">
          <div className="bg-blue-100 text-blue-600 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-6">
            <Lock size={32} />
          </div>
          <h2 className="text-2xl font-bold text-gray-900 mb-2">Enter Secure PIN</h2>
          <p className="text-gray-500 mb-8">Confirm this {transferType} transfer by entering your 4-digit PIN code.</p>

          <form onSubmit={handlePinSubmit} className="space-y-6">
            <div className="flex justify-center gap-3 mb-4">
              {[0, 1, 2, 3].map((i) => (
                <div key={i} className={`w-4 h-4 rounded-full border-2 border-blue-600 ${pin.length > i ? 'bg-blue-600' : 'bg-transparent'}`} />
              ))}
            </div>
            <input
              autoFocus
              type="password"
              maxLength={4}
              className="sr-only"
              value={pin}
              onChange={(e) => setPin(e.target.value.replace(/\D/g, ''))}
            />
            <div className="grid grid-cols-3 gap-3">
              {[1, 2, 3, 4, 5, 6, 7, 8, 9, 'C', 0, '✓'].map((num) => (
                <button
                  key={num}
                  type="button"
                  onClick={() => {
                    if (num === 'C') setPin('');
                    else if (num === '✓') { if(pin.length === 4) handlePinSubmit({ preventDefault: () => {} } as any); }
                    else if (pin.length < 4) setPin(prev => prev + num);
                  }}
                  className="h-14 bg-slate-50 hover:bg-slate-100 rounded-xl text-xl font-bold text-gray-700 active:scale-95 transition-all"
                >
                  {num}
                </button>
              ))}
            </div>

            <button
              type="submit"
              disabled={pin.length < 4}
              className="w-full bg-blue-600 hover:bg-blue-700 disabled:bg-gray-300 text-white font-bold py-4 rounded-2xl shadow-lg transition-all flex items-center justify-center gap-2"
            >
              Verify & Complete Transfer
              <ArrowRight size={20} />
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-2xl mx-auto animate-in fade-in duration-500">
      <button 
        onClick={onCancel}
        className="flex items-center gap-2 text-gray-500 hover:text-gray-800 font-medium mb-6 transition-colors"
      >
        <ArrowLeft size={20} />
        Back to Dashboard
      </button>

      <div className="bg-white rounded-3xl border border-gray-100 shadow-xl overflow-hidden">
        <div className="bg-slate-50 p-6 border-b border-gray-100">
          <h2 className="text-xl font-bold text-gray-900">New Money Transfer</h2>
          <p className="text-sm text-gray-500">Select transfer destination and enter details.</p>
        </div>

        <div className="p-8 space-y-8">
          {/* Transfer Type Selector */}
          <div className="space-y-3">
            <label className="text-sm font-semibold text-gray-700 uppercase tracking-wider">Transfer Destination</label>
            <div className="grid grid-cols-2 gap-4">
              <button
                type="button"
                onClick={() => handleTypeChange('EU')}
                className={`flex items-center justify-center gap-3 p-4 rounded-2xl border-2 transition-all font-bold ${
                  transferType === 'EU' 
                    ? 'border-blue-600 bg-blue-50 text-blue-700' 
                    : 'border-gray-100 bg-white text-gray-500 hover:border-gray-200'
                }`}
              >
                <Globe size={20} />
                International / EU
              </button>
              <button
                type="button"
                onClick={() => handleTypeChange('US')}
                className={`flex items-center justify-center gap-3 p-4 rounded-2xl border-2 transition-all font-bold ${
                  transferType === 'US' 
                    ? 'border-blue-600 bg-blue-50 text-blue-700' 
                    : 'border-gray-100 bg-white text-gray-500 hover:border-gray-200'
                }`}
              >
                <Flag size={20} />
                US Domestic
              </button>
            </div>
          </div>

          <form onSubmit={handleContinue} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-sm font-semibold text-gray-700 flex items-center gap-2">
                  <User size={16} className="text-blue-500" />
                  Recipient Full Name
                </label>
                <input
                  required
                  className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-600 outline-none"
                  placeholder="Full Name"
                  value={formData.recipientName}
                  onChange={e => setFormData({ ...formData, recipientName: e.target.value })}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-semibold text-gray-700 flex items-center gap-2">
                  <Building size={16} className="text-blue-500" />
                  Recipient Bank
                </label>
                <select
                  className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-600 outline-none bg-white"
                  value={formData.bankName}
                  onChange={e => setFormData({ ...formData, bankName: e.target.value })}
                >
                  {(transferType === 'EU' ? EU_BANKS : US_BANKS).map(bank => (
                    <option key={bank} value={bank}>{bank}</option>
                  ))}
                </select>
              </div>
            </div>

            {transferType === 'EU' ? (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-gray-700 flex items-center gap-2">
                    <CreditCard size={16} className="text-blue-500" />
                    IBAN
                  </label>
                  <input
                    required
                    className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-600 outline-none uppercase font-mono"
                    placeholder="FIXX XXXX XXXX XXXX XX"
                    value={formData.recipientIban}
                    onChange={e => setFormData({ ...formData, recipientIban: e.target.value.toUpperCase() })}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-gray-700">BIC / SWIFT (Optional)</label>
                  <input
                    className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-600 outline-none uppercase font-mono"
                    placeholder="XXXXXXXX"
                    value={formData.bicSwift}
                    onChange={e => setFormData({ ...formData, bicSwift: e.target.value.toUpperCase() })}
                  />
                </div>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-gray-700 flex items-center gap-2">
                    <CreditCard size={16} className="text-blue-500" />
                    Account Number
                  </label>
                  <input
                    required
                    className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-600 outline-none font-mono"
                    placeholder="000123456789"
                    value={formData.accountNumber}
                    onChange={e => setFormData({ ...formData, accountNumber: e.target.value.replace(/\D/g, '') })}
                  />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-gray-700">Routing Number</label>
                  <input
                    required
                    className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-600 outline-none font-mono"
                    placeholder="021000021"
                    value={formData.routingNumber}
                    onChange={e => setFormData({ ...formData, routingNumber: e.target.value.replace(/\D/g, '') })}
                  />
                </div>
              </div>
            )}

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-sm font-semibold text-gray-700">Amount (EUR)</label>
                <div className="relative">
                  <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 font-bold">€</span>
                  <input
                    required
                    type="number"
                    step="0.01"
                    min="0.01"
                    className="w-full pl-8 pr-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-600 outline-none text-xl font-bold"
                    placeholder="0.00"
                    value={formData.amount}
                    onChange={e => setFormData({ ...formData, amount: e.target.value })}
                  />
                </div>
              </div>
              <div className="space-y-2">
                <label className="text-sm font-semibold text-gray-700 flex items-center gap-2">
                  <MessageSquare size={16} className="text-blue-500" />
                  Description
                </label>
                <input
                  required
                  className="w-full px-4 py-3 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-600 outline-none"
                  placeholder="Transfer reference"
                  value={formData.description}
                  onChange={e => setFormData({ ...formData, description: e.target.value })}
                />
              </div>
            </div>

            <button
              type="submit"
              className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 rounded-2xl shadow-lg transition-all flex items-center justify-center gap-2 group"
            >
              Review & Continue
              <ChevronRight size={20} className="group-hover:translate-x-1 transition-transform" />
            </button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default TransferForm;

import React, { useState, useEffect } from 'react';
import { AppView, TransferDetails } from './types';
import { USER_CREDENTIALS, USER_PASSWORD, STATIC_USER } from './constants';
import Login from './components/Login';
import Dashboard from './components/Dashboard';
import TransferForm from './components/TransferForm';
import TransactionHistoryView from './components/TransactionHistoryView';
import Receipt from './components/Receipt';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import ProfileView from './components/ProfileView';

const App: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState<boolean>(() => {
    return localStorage.getItem('acron_auth') === 'true';
  });
  const [currentView, setCurrentView] = useState<AppView>('dashboard');
  const [lastTransfer, setLastTransfer] = useState<TransferDetails | null>(null);

  useEffect(() => {
    if (!isLoggedIn) {
      setCurrentView('login');
    }
  }, [isLoggedIn]);

  const handleLogin = (accountNumber: string, password?: string) => {
    if (accountNumber === USER_CREDENTIALS && password === USER_PASSWORD) {
      setIsLoggedIn(true);
      localStorage.setItem('acron_auth', 'true');
      setCurrentView('dashboard');
      return true;
    }
    return false;
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    localStorage.removeItem('acron_auth');
    setCurrentView('login');
  };

  const handleTransferComplete = (details: TransferDetails) => {
    setLastTransfer(details);
    setCurrentView('receipt');
  };

  if (!isLoggedIn) {
    return <Login onLogin={handleLogin} />;
  }

  const renderView = () => {
    switch (currentView) {
      case 'dashboard':
        return <Dashboard 
          user={STATIC_USER} 
          onAction={(view) => setCurrentView(view as AppView)} 
        />;
      case 'transfer':
        return <TransferForm 
          onComplete={handleTransferComplete} 
          onCancel={() => setCurrentView('dashboard')} 
        />;
      case 'history':
        return <TransactionHistoryView />;
      case 'receipt':
        return lastTransfer ? (
          <Receipt 
            details={lastTransfer} 
            onClose={() => setCurrentView('dashboard')} 
          />
        ) : <Dashboard user={STATIC_USER} onAction={(v) => setCurrentView(v as AppView)} />;
      case 'profile':
        return <ProfileView user={STATIC_USER} />;
      default:
        return <Dashboard user={STATIC_USER} onAction={(v) => setCurrentView(v as AppView)} />;
    }
  };

  return (
    <div className="flex flex-col lg:flex-row min-h-screen bg-slate-50">
      <div className="no-print">
        <Sidebar currentView={currentView} setView={setCurrentView} onLogout={handleLogout} />
      </div>
      <div className="flex-1 flex flex-col min-w-0">
        <div className="no-print">
          <Header user={STATIC_USER} currentView={currentView} setView={setCurrentView} onLogout={handleLogout} />
        </div>
        <main className="flex-1 p-4 md:p-8 max-w-7xl mx-auto w-full">
          {renderView()}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { ShieldCheck, Landmark, AlertCircle, Eye, EyeOff } from 'lucide-react';

interface LoginProps {
  onLogin: (account: string, password?: string) => boolean;
}

const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [accountNumber, setAccountNumber] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const success = onLogin(accountNumber, password);
    if (!success) {
      setError('Invalid credentials. Please verify your account number and password.');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-blue-700 to-indigo-900 px-4">
      <div className="bg-white p-8 rounded-2xl shadow-2xl w-full max-w-md">
        <div className="flex flex-col items-center mb-8">
          <div className="bg-blue-600 p-3 rounded-xl mb-4 text-white">
            <Landmark size={40} />
          </div>
          <h1 className="text-3xl font-bold text-gray-900 tracking-tight">Acron Bank</h1>
          <p className="text-gray-500 mt-2 text-center">Private Banking Online Portal</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-2">
              Account Number
            </label>
            <input
              type="text"
              required
              className="w-full px-4 py-3 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-600 focus:border-transparent outline-none transition-all placeholder:text-gray-400"
              placeholder="e.g. FI74-XXXX-XXXX-XXXX"
              value={accountNumber}
              onChange={(e) => {
                setAccountNumber(e.target.value);
                setError('');
              }}
            />
          </div>

          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-2">
              Password
            </label>
            <div className="relative">
              <input
                type={showPassword ? "text" : "password"}
                required
                className="w-full px-4 py-3 rounded-lg border border-gray-300 focus:ring-2 focus:ring-blue-600 focus:border-transparent outline-none transition-all placeholder:text-gray-400"
                placeholder="Enter your password"
                value={password}
                onChange={(e) => {
                  setPassword(e.target.value);
                  setError('');
                }}
              />
              <button
                type="button"
                className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600"
                onClick={() => setShowPassword(!showPassword)}
              >
                {showPassword ? <EyeOff size={20} /> : <Eye size={20} />}
              </button>
            </div>
          </div>

          {error && (
